import clsx from 'clsx';
import * as React from 'react';
import { isFunction } from '../util';
import { SpinLoadingSvg } from '../_assets/svgs';
import { useSelectListCssScope } from './common';
import { SelectContext } from './context/SelectContext';

/**
 * 选择器弹层空状态子组件
 * - 包含了空状态逻辑
 * - 包含了弹层的边框样式
 * - 样式写在 select 里面，select、tree-select、cascader 共享
 */
export const SelectOverlayContainer = ({
  className,
  optionsLength,
  filteredOptionsLength,
  menu,
}: {
  className?: string;
  /** 过滤前的 options 个数 */
  optionsLength: number;
  /** 过滤后的菜单项目个数，如果是 0 则会走空状态逻辑 */
  filteredOptionsLength: number;
  /** menu 是 overlay 不空的时候展示的菜单组件 */
  menu: React.ReactElement;
}) => {
  const { loading, noOptionsContent, notFoundContent, dropdownRender, inputValue } = React.useContext(SelectContext);
  const selectListCssScope = useSelectListCssScope();
  const wrapperClassName = clsx(selectListCssScope(), className);
  if (loading) {
    return (
      <div className={wrapperClassName}>
        <div className={selectListCssScope('__loading-container')}>
          <SpinLoadingSvg />
        </div>
      </div>
    );
  }
  if (!optionsLength) {
    if (noOptionsContent === null) {
      return null;
    }
    return (
      <div className={wrapperClassName}>
        <div className={selectListCssScope('__empty')}>{noOptionsContent}</div>
      </div>
    );
  }
  if (!filteredOptionsLength) {
    if (notFoundContent === null || !inputValue) {
      return null;
    }
    return (
      <div className={wrapperClassName}>
        <div className={selectListCssScope('__empty')}>{notFoundContent}</div>
      </div>
    );
  }
  if (isFunction(dropdownRender)) {
    return <div className={wrapperClassName}>{dropdownRender(menu)}</div>;
  }
  return <div className={wrapperClassName}>{menu}</div>;
};
